  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Chronologie de l'Affaire BitClub Network</text>
  <g font-family="sans-serif">
    <line x1="40" y1="60" x2="40" y2="410" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="40" cy="70" r="6" fill="#f59e0b"/>
